class Solution:
    def popcountDepth(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        def popcount(x):
            count = 0
            while x:
                count += x & 1
                x >>= 1
            return count

        def popcount_depth(x):
            depth = 0
            while x > 1:
                x = popcount(x)
                depth += 1
            return depth

        answer = []
        for query in queries:
            if query[0] == 1:
                l, r, k = query[1], query[2], query[3]
                count = sum(1 for i in range(l, r + 1) if popcount_depth(nums[i]) == k)
                answer.append(count)
            elif query[0] == 2:
                idx, val = query[1], query[2]
                nums[idx] = val
        return answer
